using Microsoft.EntityFrameworkCore;

// Cosmos DB context demonstrating EF Core 9 breaking change fixes.
class CosmosContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    public DbSet<DiscountedProduct> DiscountedProducts => Set<DiscountedProduct>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>()
            .ToContainer("Products")
            .HasPartitionKey(p => p.Category);

        // BREAKING CHANGE FIX: EF Core 9 changed the default discriminator
        // property from "Discriminator" to "$type". Existing Cosmos documents
        // still store "Discriminator", so we must explicitly configure the old name
        // to avoid query mismatches and data corruption.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Category { get; set; } = default!;
    public string Name { get; set; } = default!;
}

class DiscountedProduct : Product
{
    public decimal Discount { get; set; }
}

// BREAKING CHANGE FIX: EF Core 9 removed synchronous Cosmos DB query support.
// Sync calls like .ToList(), .First(), .Count() now throw
// InvalidOperationException. All queries must use async equivalents.
class CosmosCatalogService
{
    private readonly CosmosContext _db;

    public CosmosCatalogService(CosmosContext db) => _db = db;

    // BEFORE (EF Core 8 – sync, now throws in EF Core 9):
    //   var products = _db.Products.Where(p => p.Category == category).ToList();
    //   var first    = _db.Products.First(p => p.Id == id);
    //   var count    = _db.Products.Count();

    // AFTER (EF Core 9 – async equivalents):
    public async Task<List<Product>> GetByCategoryAsync(string category)
        => await _db.Products.Where(p => p.Category == category).ToListAsync();

    public async Task<Product> GetByIdAsync(string id)
        => await _db.Products.FirstAsync(p => p.Id == id);

    public async Task<int> CountAsync()
        => await _db.Products.CountAsync();
}

